/* com.erns.coching.mail.mapper.FcmPushDAO.selectWillSend */
SELECT
FROM T_BATCH_MAIL AA
AND AA.RESULT in ('R', 'F') AND AA.ERR_CNT < 3 AND TO_DATE(AA.SEND_DATE, 'YYYY-MM-DD HH24:mi:SS') < SYSDATE AND ROWNUM < #{value ,jdbcType=INTEGER}
ORDER BY AA.BATCH_SEQ ASC

		/* com.erns.coching.mail.mapper.FcmPushDAO.load */

		SELECT

        FROM T_BATCH_MAIL AA


        	AND AA.BATCH_SEQ = #{value	,jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.mail.mapper.MailDAO.insert */

	SELECT nextval('seq_t_batch_mail')


INSERT INTO T_BATCH_MAIL (
BATCH_SEQ
, RESULT
, RESULT_DATA
, ERR_CNT
, SEND_DATE
, SENT_DATE
, MEMB_SEQ
, TO_EMAIL
, PRIORITY
, TITLE
, CONTENT
, MAIL_SEQ
, FILE_ID
)
VALUES (
#{batchSeq	,jdbcType=INTEGER}
, 'R'
, NULL
, 0
, COALESCE(#{sendDate	,jdbcType=VARCHAR}
, TO_CHAR(now(), 'YYYY-MM-DD HH24:mi:SS'))
, NULL
, #{membSeq     ,jdbcType=INTEGER}
, #{toEmail		,jdbcType=VARCHAR}
, #{priority	,jdbcType=VARCHAR}
, #{title		,jdbcType=VARCHAR}
, #{content		,jdbcType=VARCHAR}
, #{mailSeq		,jdbcType=INTEGER}
, #{fileId		,jdbcType=VARCHAR}
)

mapper.update:
/* com.erns.coching.mail.mapper.FcmPushDAO.updateSuccess */

UPDATE T_BATCH_MAIL SET
	  RESULT = 'S'
	, RESULT_DATA = #{resultData,	jdbcType=VARCHAR}
	, SENT_DATE = SYSDATE
	, CHNG_DTTM = SYSDATE

WHERE BATCH_SEQ = #{batchSeq	,jdbcType=INTEGER}

/* com.erns.coching.mail.mapper.FcmPushDAO.updateFail */

UPDATE T_BATCH_MAIL SET
	  RESULT = NVL(#{result,	jdbcType=VARCHAR}, 'F')
	, RESULT_DATA 	= #{resultData,	jdbcType=VARCHAR}
	, ERR_CNT 		= ERR_CNT + 1
	, CHNG_DTTM		= SYSDATE

WHERE BATCH_SEQ 	= #{batchSeq	,jdbcType=INTEGER}
